// ─── Daily Challenge helpers ──────────────────────────────────────────────────
const getTodayUTC = () => new Date().toISOString().slice(0, 10);

// Deterministic Fisher-Yates using a 32-bit LCG. Changing DAILY_SEED resets
// the cycle for all players (do this deliberately on major library updates).
const DAILY_SEED = 0xE19161;
const DAILY_EPOCH = '2025-01-01';

const _seededShuffle = (arr, seed) => {
  const a = [...arr];
  let s = seed >>> 0;
  for (let i = a.length - 1; i > 0; i--) {
    s = (Math.imul(s, 1664525) + 1013904223) >>> 0;
    const j = s % (i + 1);
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
};

let _dailyFlatCache = null;
const _getDailyFlat = () => {
  if (!_dailyFlatCache) {
    const flat = Object.keys(CONTENT_LIBRARY).flatMap(id =>
      CONTENT_LIBRARY[id].map(item => ({ themeId: id, item }))
    );
    _dailyFlatCache = _seededShuffle(flat, DAILY_SEED);
  }
  return _dailyFlatCache;
};

const _dayNumber = (dateStr) =>
  Math.floor((new Date(dateStr).getTime() - new Date(DAILY_EPOCH).getTime()) / 86400000);

const getDailyChallenge = () => {
  const today = getTodayUTC();
  const flat = _getDailyFlat();
  const picked = flat[_dayNumber(today) % flat.length];
  const theme = THEMES.find((t) => t.id === picked.themeId) || THEMES[0];
  return { theme, item: picked.item, date: today };
};

// Returns the Set of secret strings scheduled as daily challenges for the
// next `days` days (including today). Used to keep solo from spoiling them.
const getUpcomingDailySecrets = (days = 14) => {
  const flat = _getDailyFlat();
  const today = getTodayUTC();
  const base = _dayNumber(today);
  const out = new Set();
  for (let i = 0; i < days; i++) out.add(flat[(base + i) % flat.length].item.secret);
  return out;
};

// ─── Player identity & seen-secrets (Supabase + AsyncStorage cache) ───────────
const _seenCacheKey = (tier) => `enigma_seen_v1_${tier}`;

const _generateUUID = () =>
  'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = (Math.random() * 16) | 0;
    return (c === 'x' ? r : (r & 0x3) | 0x8).toString(16);
  });

const getOrCreatePlayerId = async () => {
  try {
    const stored = await AsyncStorage.getItem('enigma_player_id_v1');
    if (stored) return stored;
    const id = _generateUUID();
    await AsyncStorage.setItem('enigma_player_id_v1', id);
    await supabase.from('player_profiles').upsert({ id }, { onConflict: 'id' });
    return id;
  } catch {
    return null;
  }
};

const loadSeenSecrets = async (playerId, tier) => {
  if (!playerId) return new Set();
  try {
    const { data, error } = await supabase
      .from('player_seen_secrets')
      .select('secret')
      .eq('player_id', playerId)
      .eq('tier', tier);
    if (!error && data) {
      const seen = new Set(data.map(r => r.secret));
      await AsyncStorage.setItem(_seenCacheKey(tier), JSON.stringify([...seen]));
      return seen;
    }
  } catch {}
  // Offline fallback — use local cache
  try {
    const cached = await AsyncStorage.getItem(_seenCacheKey(tier));
    if (cached) return new Set(JSON.parse(cached));
  } catch {}
  return new Set();
};

const markSecretSeen = async (playerId, secret, tier) => {
  // Update local cache immediately so the next pick is correct even offline
  try {
    const cached = await AsyncStorage.getItem(_seenCacheKey(tier));
    const arr = cached ? JSON.parse(cached) : [];
    if (!arr.includes(secret)) {
      arr.push(secret);
      await AsyncStorage.setItem(_seenCacheKey(tier), JSON.stringify(arr));
    }
  } catch {}
  if (!playerId) return;
  try {
    await supabase.from('player_seen_secrets').upsert(
      { player_id: playerId, secret, tier, seen_at: new Date().toISOString() },
      { onConflict: 'player_id,secret,tier' }
    );
  } catch {}
};

// Called when the available pool for a tier is exhausted.
// Fetches the 30 most-recently-seen from Supabase (ordered by seen_at),
// deletes everything else, so the player gets a fresh start while avoiding
// immediate repeats of what they just played.
const resetSeenForExhaustion = async (playerId, tier) => {
  let keepSet = new Set();
  if (playerId) {
    try {
      const { data } = await supabase
        .from('player_seen_secrets')
        .select('secret')
        .eq('player_id', playerId)
        .eq('tier', tier)
        .order('seen_at', { ascending: false })
        .limit(30);
      if (data) keepSet = new Set(data.map(r => r.secret));
      await supabase.from('player_seen_secrets').delete()
        .eq('player_id', playerId).eq('tier', tier);
      if (keepSet.size > 0) {
        await supabase.from('player_seen_secrets').insert(
          [...keepSet].map(s => ({ player_id: playerId, secret: s, tier, seen_at: new Date().toISOString() }))
        );
      }
    } catch {}
  }
  try {
    await AsyncStorage.setItem(_seenCacheKey(tier), JSON.stringify([...keepSet]));
  } catch {}
  return keepSet;
};

// ─── Solo lifetime stats (local-only, AsyncStorage) ───────────────────────────
const _SOLO_STATS_KEY = 'enigma_solo_stats_v1';
const DEFAULT_SOLO_STATS = { gamesPlayed: 0, wins: 0, currentStreak: 0, bestStreak: 0, bestQuestions: null };

const loadSoloStats = async () => {
  try {
    const raw = await AsyncStorage.getItem(_SOLO_STATS_KEY);
    if (raw) return { ...DEFAULT_SOLO_STATS, ...JSON.parse(raw) };
  } catch {}
  return { ...DEFAULT_SOLO_STATS };
};

// Pure reducer — returns the updated stats for one finished solo round.
const nextSoloStats = (prev, solved, questionsUsed) => {
  const s = { ...DEFAULT_SOLO_STATS, ...prev };
  s.gamesPlayed += 1;
  if (solved) {
    s.wins += 1;
    s.currentStreak += 1;
    if (s.currentStreak > s.bestStreak) s.bestStreak = s.currentStreak;
    if (s.bestQuestions == null || questionsUsed < s.bestQuestions) s.bestQuestions = questionsUsed;
  } else {
    s.currentStreak = 0;
  }
  return s;
};

const persistSoloStats = async (stats) => {
  try { await AsyncStorage.setItem(_SOLO_STATS_KEY, JSON.stringify(stats)); } catch {}
};

// ─── Fact-card images (Wikipedia/Wikimedia, runtime, best-effort) ─────────────
// Loads a thumbnail for the secret at result time. No manual sourcing or bundling;
// Commons images are freely licensed. Returns null (→ no image, card unchanged)
// whenever there's no clean match, a network error, or a sensitive subject.
//
// Sensitivity guard: never show images for prophets / key religious figures.
// Matched case-insensitively; anything beginning with "Prophet " is also skipped.
const NO_IMAGE_SECRETS = new Set([
  'prophet muhammad', 'prophet adam', 'prophet noah', 'prophet abraham',
  'prophet david', 'prophet solomon', 'prophet moses', 'prophet jesus',
  'jesus', 'jesus christ', 'allah', 'kaaba', 'the kaaba',
]);

const _imageBlocked = (secret) => {
  const s = (secret || '').trim().toLowerCase();
  return s.startsWith('prophet ') || NO_IMAGE_SECRETS.has(s);
};

// "Petra (The Rose City)" → "Petra"; an explicit `wiki` override always wins.
const _wikiTitle = (secret, override) => {
  if (override) return override;
  return (secret || '').replace(/\s*\([^)]*\)\s*/g, ' ').trim();
};

const fetchSecretImage = async (secret, override) => {
  if (_imageBlocked(secret)) return null;
  const title = _wikiTitle(secret, override);
  if (!title) return null;
  try {
    const res = await fetch(
      `https://en.wikipedia.org/api/rest_v1/page/summary/${encodeURIComponent(title)}?redirect=true`,
      { headers: {
        Accept: 'application/json',
        // Wikipedia asks API clients to identify themselves.
        'Api-User-Agent': 'EnigmaGame/1.0 (20-questions party game; contact via app store listing)',
      } }
    );
    if (!res.ok) return null;
    const data = await res.json();
    // Disambiguation pages rarely have a relevant image — skip them.
    if (data.type && String(data.type).includes('disambiguation')) return null;
    return data.thumbnail?.source || null;
  } catch {
    return null;
  }
};

const SERVER_URL = Constants.expoConfig?.extra?.serverUrl || 'https://enigma-game-production.up.railway.app';

// Appended to shared result text. Set to the App Store / TestFlight link when live.
const SHARE_URL = Constants.expoConfig?.extra?.shareUrl || '';

// Builds the SPOILER-FREE daily share text (Wordle-style): performance only,
// never the secret or category. Date identifies the puzzle, like Wordle's number.
const buildDailyShareText = ({ solved, questionsUsed, timeSeconds }) => {
  const rating = dailyStars(questionsUsed, solved);
  const dateStr = new Date().toLocaleDateString('en-GB', { day: 'numeric', month: 'short' });
  const stars = rating.stars > 0 ? ' ' + '✦'.repeat(rating.stars) : '';
  const mins = Math.floor((timeSeconds || 0) / 60);
  const secs = (timeSeconds || 0) % 60;
  const timeStr = mins > 0 ? `${mins}m ${secs}s` : `${secs}s`;
  const lines = [`🕵️ 20Q — Daily Challenge · ${dateStr}`];
  if (solved) {
    lines.push(`Solved in ${questionsUsed} question${questionsUsed !== 1 ? 's' : ''}${stars} (${timeStr})`);
    lines.push('', "Can you beat today's mystery?");
  } else {
    lines.push("Today's mystery got me — can you crack it?");
  }
  if (SHARE_URL) lines.push('', SHARE_URL);
  return lines.join('\n');
};

// Keeps Railway server warm — pings every 4 minutes so it never sleeps
const pingServer = () => fetch(`${SERVER_URL}/api/ping`).catch(() => {});

// Silent retry with 5-minute deadline. Returns YES/NO/PARTLY on success,
// or 'TIMEOUT' if the device has no connection after 5 minutes of trying.
const askWithRetry = async (payload, maxWaitMs = 5 * 60 * 1000) => {
  const deadline = Date.now() + maxWaitMs;
  let delay = 2000;
  while (Date.now() < deadline) {
    try {
      const controller = new AbortController();
      const timer = setTimeout(() => controller.abort(), 12000);
      const res = await fetch(`${SERVER_URL}/api/ask`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
        signal: controller.signal,
      });
      clearTimeout(timer);
      const data = await res.json();
      if (data.answer && ['YES', 'NO', 'PARTLY'].includes(data.answer)) return data.answer;
    } catch {
      // swallow and retry
    }
    await new Promise(r => setTimeout(r, delay));
    delay = Math.min(delay * 1.5, 8000);
  }
  return 'TIMEOUT';
};

// Returns true only for properly-formed yes/no questions.
// Rejects one-word fragments, dangling starters ("Is it", "As"), and
// anything that isn't a real sentence the AI can evaluate.
// Words that carry no meaning on their own. A question is accepted as long as
// it contains at least one token that ISN'T in this set — so keyword-style
// queries ("alive", "a scientific event") pass, while lone fillers ("how",
// "the", "one", "is it") are rejected before they reach the AI.
const STOPWORDS = new Set([
  // articles / determiners
  'a','an','the','this','that','these','those','some','any','no','each','every',
  // pronouns
  'it','he','she','they','them','we','you','i','him','her','his','its','their','your','our',
  // auxiliary / linking verbs
  'is','are','was','were','be','been','being','am','do','does','did','has','have','had',
  'can','could','will','would','shall','should','may','might','must',
  // lone question words
  'how','what','who','whom','whose','why','when','where','which',
  // conjunctions / prepositions
  'and','or','but','of','to','in','on','at','by','for','with','as','from','about',
  'than','then','so','if','into','over','under','out','up','down',
  // generic fillers
  'one','ones','thing','things','something','anything','someone','anyone',
  'yes','no','maybe','ok','okay','um','uh','hmm','please','just','really',
]);

// Common short (≤3 letter) content words. Short tokens are the main home of
// random gibberish ("inz", "tvr"), so a short token only counts as real if it
// appears here — while longer tokens are validated structurally below.
const SHORT_WORDS = new Set([
  'ox','ax','pi','tv','id','ad','cd',
  'act','age','aid','aim','air','ale','amp','ant','ape','apt','arc','ark','arm','art','ash','ask','axe',
  'bad','bag','ban','bar','bat','bay','bed','bee','beg','bet','bid','big','bin','bit','boa','bob','bog','bot','bow','box','boy','bra','bud','bug','bun','bus','buy',
  'cab','cam','cap','car','cat','cob','cod','cog','con','cop','cot','cow','cry','cub','cue','cup','cut',
  'dad','dam','day','den','dew','die','dig','dim','din','dip','doe','dog','dot','dry','dub','due','dug','dye',
  'ear','eat','eel','egg','ego','elf','elk','elm','emu','end','era','eve','ewe','eye',
  'fad','fan','far','fat','fax','fee','fen','fib','fig','fin','fir','fit','fix','flu','fly','foe','fog','fox','fry','fun','fur',
  'gag','gap','gas','gel','gem','gig','gin','god','gum','gun','gut','guy','gym',
  'ham','hat','hay','hem','hen','hex','hip','hit','hoe','hog','hop','hot','hub','hue','hug','hum','hut',
  'ice','icy','ill','imp','ink','inn','ion','ire','ivy','jab','jam','jar','jaw','jay','jet','jig','job','jog','jot','joy','jug',
  'keg','key','kid','kin','kit','lab','lad','lag','lap','law','lay','leg','lid','lie','lip','lit','lob','log','lot','low','lug',
  'mad','man','map','mar','mat','men','met','mix','mob','mod','mop','mud','mug','mum',
  'nag','nap','net','nib','nip','nod','nub','nun','nut','oak','oar','oat','odd','ode','oil','old','orb','ore','owl',
  'pad','pal','pan','par','pat','paw','pea','peg','pen','pet','pie','pig','pin','pit','pod','pot','pro','pub','pug','pun','pup','put',
  'rag','ram','rap','rat','raw','ray','red','rib','rig','rim','rip','rob','rod','roe','rot','row','rub','rug','rum','run','rye',
  'sac','sad','sag','sap','saw','sax','sea','see','set','sin','sip','sir','sit','six','ski','sky','sly','sob','sod','son','sow','soy','spa','spy','sub','sum','sun',
  'tab','tag','tan','tap','tar','tax','tea','ten','tie','tin','tip','toe','ton','top','toy','try','tub','tug','two',
  'urn','use','van','vat','vet','via','vow','wad','wag','war','wax','way','web','wed','wig','win','wit','woe','wok','won','yak','yam','yen','yew','zap','zip','zoo',
]);

const VOWELS = new Set(['a','e','i','o','u','y']);

// Does a single non-stopword token look like a real word (vs. gibberish)?
const looksLikeWord = (w) => {
  if (/[0-9]/.test(w)) return true;             // years/numbers are meaningful ("1900s")
  if (w.length <= 3) return SHORT_WORDS.has(w);  // short → must be a known word
  if (![...w].some((c) => VOWELS.has(c))) return false;  // longer words need a vowel
  let run = 0;                                   // reject 4+ consonants in a row
  for (const c of w) { if (VOWELS.has(c)) run = 0; else if (++run >= 4) return false; }
  return true;
};

const isValidQuestion = (text) => {
  const cleaned = (text || '').trim().toLowerCase().replace(/\?+$/, '').trim();
  if (!cleaned) return false;
  const words = cleaned.split(/\s+/).map((w) => w.replace(/[^a-z0-9]/g, '')).filter(Boolean);
  // Accept if at least one real, meaningful (non-filler, word-like) token exists.
  return words.some((w) => !STOPWORDS.has(w) && looksLikeWord(w));
};

const dailyStars = (questions, solved) => {
  if (!solved) return { stars: 0, label: 'Better luck tomorrow!' };
  if (questions <= 5)  return { stars: 3, label: 'Legendary! ✦✦✦' };
  if (questions <= 10) return { stars: 2, label: 'Expert! ✦✦' };
  if (questions <= 15) return { stars: 1, label: 'Good! ✦' };
  return { stars: 0, label: 'Squeaked it!' };
};

